import{_ as a,o as s,c as t,a0 as n}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Locked Instances & Unlock Requests","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/session-lock.md","filePath":"how-to/session-lock.md"}'),o={name:"how-to/session-lock.md"};function i(l,e,r,c,h,d){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="locked-instances-unlock-requests" tabindex="-1">Locked Instances &amp; Unlock Requests <a class="header-anchor" href="#locked-instances-unlock-requests" aria-label="Permalink to &quot;Locked Instances &amp; Unlock Requests&quot;">​</a></h1><p>Instances do not stay open forever. After an event ends, the tracker gives a short cleanup window and then locks the instance to protect history from late changes.</p><blockquote><p>Screenshot placeholder: session-locked.png</p></blockquote><h2 id="the-rule" tabindex="-1">The rule <a class="header-anchor" href="#the-rule" aria-label="Permalink to &quot;The rule&quot;">​</a></h2><p>An instance auto-locks <strong>3 days after it ends</strong>.</p><p>After that:</p><ul><li>new imports are blocked</li><li>edits are blocked</li><li>manual cleanup is blocked</li></ul><p>If you try anyway, you hit a lock error and need an unlock.</p><h2 id="the-unlock-flow" tabindex="-1">The unlock flow <a class="header-anchor" href="#the-unlock-flow" aria-label="Permalink to &quot;The unlock flow&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;Event instance ends&quot;] --&gt; B[&quot;3-day cleanup window&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;Instance auto-locks&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;User tries to import or edit&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;Lock error shown&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[&quot;User sends unlock request&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[&quot;King / Alliance Leader / Supreme Admin reviews&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[&quot;Approve unlock&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; I[&quot;Reject unlock&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; J[&quot;Instance opens again for changes&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; K[&quot;Instance stays locked&quot;]</span></span></code></pre></div><h2 id="what-editors-see" tabindex="-1">What editors see <a class="header-anchor" href="#what-editors-see" aria-label="Permalink to &quot;What editors see&quot;">​</a></h2><p>On a locked session, non-admin editors see a <strong>Request Unlock</strong> area with:</p><ul><li>a reason box</li><li>a <strong>Send unlock request</strong> action</li></ul><p>This is your chance to explain what still needs to be fixed.</p><h2 id="what-reviewers-do" tabindex="-1">What reviewers do <a class="header-anchor" href="#what-reviewers-do" aria-label="Permalink to &quot;What reviewers do&quot;">​</a></h2><p>An authorized reviewer can:</p><ul><li>unlock directly</li><li>approve an unlock request</li><li>reject an unlock request</li></ul><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>use the 3-day window for cleanup as much as possible</li><li>explain exactly what needs fixing in your unlock request</li><li>do not request unlock &quot;just in case&quot;</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./instance-detail.html">Work Inside an Instance</a></li><li><a href="./../troubleshooting/imports.html">Import &amp; OCR Problems</a></li></ul>`,21)])])}const k=a(o,[["render",i]]);export{p as __pageData,k as default};
